import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';

const ALL_RESTAURANTS = [
  {
    id: 'spice-garden',
    name: 'Spice Garden',
    cuisine: 'North Indian · Mughlai',
    category: 'Indian',
    emoji: '🍛',
    rating: 4.6,
    time: '25–35 min',
    priceFor2: '₹200',
    isVeg: true,
    isOpen: true,
    isBusy: false,
    priceLevel: '₹₹',
    bg: 'from-indigo-950 to-indigo-900',
  },
  {
    id: 'burger-republic',
    name: 'Burger Republic',
    cuisine: 'American · Fast Food',
    category: 'Burgers',
    emoji: '🍔',
    rating: 4.3,
    time: '15–20 min',
    priceFor2: '₹350',
    isVeg: false,
    isOpen: true,
    isBusy: false,
    priceLevel: '₹₹',
    bg: 'from-emerald-950 to-emerald-900',
  },
  {
    id: 'dragon-wok',
    name: 'Dragon Wok',
    cuisine: 'Chinese · Thai',
    category: 'Chinese',
    emoji: '🍜',
    rating: 4.4,
    time: '30–40 min',
    priceFor2: '₹280',
    isVeg: false,
    isOpen: true,
    isBusy: true,
    priceLevel: '₹₹',
    bg: 'from-red-950 to-red-900',
  },
  {
    id: 'pizza-co',
    name: 'The Pizza Co.',
    cuisine: 'Italian · Wood-fired',
    category: 'Pizza',
    emoji: '🍕',
    rating: 4.5,
    time: '20–30 min',
    priceFor2: '₹400',
    isVeg: false,
    isOpen: true,
    isBusy: false,
    priceLevel: '₹₹₹',
    bg: 'from-blue-950 to-blue-900',
  },
  {
    id: 'chai-snacks',
    name: 'Chai & Snacks',
    cuisine: 'Cafe · Street Food',
    category: 'Cafe',
    emoji: '☕',
    rating: 4.2,
    time: '10–15 min',
    priceFor2: '₹100',
    isVeg: true,
    isOpen: true,
    isBusy: false,
    priceLevel: '₹',
    bg: 'from-purple-950 to-purple-900',
  },
  {
    id: 'biryani-hub',
    name: 'Biryani Hub',
    cuisine: 'Hyderabadi · Mughlai',
    category: 'Indian',
    emoji: '🫕',
    rating: 4.7,
    time: '20–30 min',
    priceFor2: '₹300',
    isVeg: false,
    isOpen: true,
    isBusy: false,
    priceLevel: '₹₹',
    bg: 'from-amber-950 to-amber-900',
  },
];

const CATEGORIES = ['All', 'Indian', 'Burgers', 'Chinese', 'Pizza', 'Cafe'];

export default function Restaurants() {
  const [search, setSearch]     = useState('');
  const [activecat, setActivecat] = useState('All');
  const [vegOnly, setVegOnly]   = useState(false);
  const { setRestaurant, clearCart } = useCart();
  const navigate = useNavigate();

  const filtered = ALL_RESTAURANTS.filter(r => {
    const matchSearch = r.name.toLowerCase().includes(search.toLowerCase()) ||
                        r.cuisine.toLowerCase().includes(search.toLowerCase());
    const matchCat    = activecat === 'All' || r.category === activecat;
    const matchVeg    = !vegOnly || r.isVeg;
    return matchSearch && matchCat && matchVeg;
  });

  const openMenu = (restaurant) => {
    clearCart();
    setRestaurant(restaurant);
    navigate(`/menu/${restaurant.id}`);
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto px-6 py-8">

        {/* Header row */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
          <div>
            <h1 className="text-2xl font-bold text-gray-900">Restaurants near you</h1>
            <p className="text-sm text-gray-500 mt-1">
              Dhanbad, Jharkhand · {filtered.length} restaurants open
            </p>
          </div>
          {/* Search */}
          <input
            type="text"
            value={search}
            onChange={e => setSearch(e.target.value)}
            placeholder="🔍  Search restaurants or dishes..."
            className="md:w-72 px-4 py-2.5 border border-gray-200 rounded-full bg-white text-sm focus:outline-none focus:ring-2 focus:ring-red-500 focus:border-transparent shadow-sm"
          />
        </div>

        {/* Filter bar */}
        <div className="flex items-center gap-2 mb-6 flex-wrap">
          {CATEGORIES.map(cat => (
            <button
              key={cat}
              onClick={() => setActivecat(cat)}
              className={`px-4 py-2 rounded-full text-sm font-medium border transition-colors ${
                activecat === cat
                  ? 'bg-red-600 text-white border-red-600'
                  : 'bg-white text-gray-600 border-gray-200 hover:border-gray-300'
              }`}
            >
              {cat}
            </button>
          ))}
          {/* Veg toggle */}
          <button
            onClick={() => setVegOnly(v => !v)}
            className={`ml-auto flex items-center gap-2 px-4 py-2 rounded-full text-sm font-medium border transition-colors ${
              vegOnly
                ? 'bg-green-600 text-white border-green-600'
                : 'bg-white text-gray-600 border-gray-200 hover:border-gray-300'
            }`}
          >
            <span className="w-3 h-3 rounded-full bg-green-500 inline-block" />
            Pure Veg
          </button>
        </div>

        {/* Restaurant grid */}
        {filtered.length === 0 ? (
          <div className="text-center py-20 text-gray-400">
            <div className="text-5xl mb-4">🍽️</div>
            <p className="text-lg font-medium">No restaurants found</p>
            <p className="text-sm mt-1">Try a different search or filter</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5">
            {filtered.map(r => (
              <RestaurantCard key={r.id} restaurant={r} onOpen={openMenu} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

function RestaurantCard({ restaurant: r, onOpen }) {
  return (
    <div
      onClick={() => onOpen(r)}
      className="bg-white border border-gray-200 rounded-2xl overflow-hidden cursor-pointer hover:shadow-md hover:border-gray-300 transition-all group"
    >
      {/* Banner */}
      <div className={`h-36 bg-gradient-to-br ${r.bg} flex items-center justify-center text-6xl relative`}>
        {r.emoji}
        {r.isBusy ? (
          <span className="absolute top-3 right-3 bg-amber-500 text-white text-xs font-semibold px-3 py-1 rounded-full">
            Busy
          </span>
        ) : (
          <span className="absolute top-3 right-3 bg-emerald-500 text-white text-xs font-semibold px-3 py-1 rounded-full">
            Open
          </span>
        )}
      </div>

      {/* Body */}
      <div className="p-4">
        <div className="flex items-start justify-between mb-1">
          <h3 className="font-semibold text-gray-900 group-hover:text-red-600 transition-colors">
            {r.name}
          </h3>
          <span className="flex items-center gap-1 text-amber-500 font-semibold text-sm">
            ★ {r.rating}
          </span>
        </div>

        <p className="text-xs text-gray-500 mb-3">{r.cuisine}</p>

        <div className="flex items-center gap-2 text-xs text-gray-500 mb-3">
          <span>⏱ {r.time}</span>
          <span>·</span>
          <span>👥 {r.priceFor2} for two</span>
        </div>

        <div className="flex items-center gap-2">
          {r.isVeg ? (
            <span className="text-xs font-medium bg-green-50 text-green-700 border border-green-200 px-2 py-0.5 rounded">
              Pure Veg
            </span>
          ) : (
            <span className="text-xs font-medium bg-red-50 text-red-700 border border-red-200 px-2 py-0.5 rounded">
              Non-Veg
            </span>
          )}
          <span className="text-xs font-medium bg-amber-50 text-amber-700 border border-amber-200 px-2 py-0.5 rounded">
            {r.priceLevel}
          </span>
        </div>
      </div>
    </div>
  );
}
